import sys
from collections import deque
class Solution:
    def maxHeapify(self, nums: list[int], n: int, i: int) -> bool:
        if i <= n // 2:
            if nums[i] < nums[2 * i]:
                nums[i], nums[2 * i] = nums[2 * i], nums[i]
                self.maxHeapify(nums, n, 2 * i)
        return True
    def solve(self):
        nums = list(map(int, input().split(' ')))
        n = int(input())
        self.maxHeapify(nums, n, n - 1)
        print(' '.join(map(str, nums)))

solution = Solution()
solution.solve()

