#include <iostream>
#include <vector>
using namespace std;
class Solution {
public:
    void maxHeapify(vector<int>& nums, int n, int i) {
        if (i <= n / 2) {
            if (nums[i] < nums[2 * i]) {
                swap(nums[i], nums[2 * i]);
                maxHeapify(nums, n, 2 * i);
            }
        }
    }
    void solve() {
        vector<int> nums;
        int n;
        cin >> n;
        for (int i = 0; i < n; i++) {
            cin >> nums[i];
        }
        maxHeapify(nums, n, n - 1);
        for (int i : nums) {
            cout << i << ' ';
        }
        cout << endl;
    }
};

int main() {
    Solution solution;
solution.solve();
cout << "Hello World!" << endl;
    return 0;
}
